loadstring(game:HttpGet("https://raw.githubusercontent.com/xHeptc/Kavo-UI-Library/main/source.lua"))() local Win = loadstring(game:HttpGet("https://raw.githubusercontent.com/xHeptc/Kavo-UI-Library/main/source.lua"))().CreateLib("👑 DSA HUB | KING AURORA", "Midnight") local Main = Win:NewTab("Main") local Sec = Main:NewSection("Player Cheats") Sec:NewButton("👁️ ESP Highlight", "View Players", function() for _, p in pairs(game.Players:GetPlayers()) do if p ~= game.Players.LocalPlayer and p.Character then local h = Instance.new("Highlight", p.Character) h.FillColor = Color3.fromRGB(0, 255, 255) h.DepthMode = "AlwaysOnTop" end end end) Sec:NewToggle("⚔️ Auto Click", "Auto Attack", function(s) _G.Active = s while _G.Active do task.wait(0.1) game:GetService("VirtualUser"):ClickButton1(Vector2.new(0,0)) end end) Sec:NewSlider("⚡ WalkSpeed", "Speed", 500, 16, function(v) game.Players.LocalPlayer.Character.Humanoid.WalkSpeed = v end)

